      "type": "heading",
      "attrs": { "level": 3 },
      "content": [{ "type": "text", "text": "SQL: полнотекстовый поиск в Postgres" }]
    },
    {
      "type": "codeBlock",
      "content": [{
        "type": "text",
        "text": "-- Создание индекса полнотекстового поиска по колонке title и body\nCREATE INDEX idx_posts_fts ON posts USING GIN (\n  to_tsvector('russian', coalesce(title,'') || ' ' || coalesce(body,''))\n);\n\n-- Поиск с учетом морфологии (plainto_tsquery удобен для пользовательского ввода)\nSELECT id, title, ts_headline('russian', body, plainto_tsquery('russian', $1)) AS snippet,\n       ts_rank_cd(\n         to_tsvector('russian', coalesce(title,'') || ' ' || coalesce(body,'')),\n         plainto_tsquery('russian', $1)\n       ) AS rank\nFROM posts\nWHERE to_tsvector('russian', coalesce(title,'') || ' ' || coalesce(body,'')) @@ plainto_tsquery('russian', $1)\nORDER BY rank DESC\nLIMIT 20 OFFSET $2;\n\n-- Пример simple LIKE (подстрочный поиск; менее эффективен)\nSELECT id, title FROM posts WHERE title ILIKE '%' || $1 || '%' LIMIT 20;"
      }]
    },
    {
      "type": "heading",
      "attrs": { "level": 3 },
      "content": [{ "type": "text", "text": "Backend: Node.js Express endpoint с пагинацией и фильтрами" }]
    },
    {
      "type": "codeBlock",
      "content": [{
        "type": "text",
        "text": "import express from 'express';\nimport { Pool } from 'pg';\n\nconst app = express();\nconst pool = new Pool({ connectionString: process.env.DATABASE_URL });\n\napp.get('/search', async (req, res) => {\n  const q = String(req.query.q || '').trim();\n  const limit = Math.min(parseInt(String(req.query.limit || '20'), 10), 100);\n  const cursor = req.query.cursor ? Number(req.query.cursor) : null; // keyset пагинация\n  const category = req.query.category ? String(req.query.category) : null;\n\n  const params = [] as any[];\n  let where = [] as string[];\n\n  if (q) {\n    params.push(q);\n    where.push(\"to_tsvector('russian', coalesce(title,'') || ' ' || coalesce(body,'')) @@ plainto_tsquery('russian', $\" + params.length + \")\");\n  }\n  if (category) {\n    params.push(category);\n    where.push('category = $' + params.length);\n  }\n  if (cursor) {\n    params.push(cursor);\n    where.push('id > $' + params.length); // keyset: сортировка по id ASC\n  }\n\n  const sql = `\n    SELECT id, title, ts_rank_cd(\n      to_tsvector('russian', coalesce(title,'') || ' ' || coalesce(body,'')),\n      COALESCE(plainto_tsquery('russian', $1), to_tsquery('russian', ''))\n    ) AS rank\n    FROM posts\n    ${where.length ? 'WHERE ' + where.join(' AND ') : ''}\n    ORDER BY id ASC\n    LIMIT ${limit + 1}\n  `;\n\n  try {\n    const { rows } = await pool.query(sql, params);\n    const hasMore = rows.length > limit;\n    const items = hasMore ? rows.slice(0, limit) : rows;\n    res.json({ items, nextCursor: hasMore ? items[items.length - 1].id : null });\n  } catch (e) {\n    res.status(500).json({ error: 'search_failed' });\n  }\n});\n\napp.listen(3000);"
      }]
    },
    {
      "type": "heading",
      "attrs": { "level": 3 },
      "content": [{ "type": "text", "text": "Frontend: React, дебаунс и отмена устаревших запросов" }]
    },
    {
      "type": "codeBlock",
      "content": [{
        "type": "text",
        "text": "import { useEffect, useMemo, useState } from 'react';\n\nfunction useDebouncedValue(value, delay = 300) {\n  const [debounced, setDebounced] = useState(value);\n  useEffect(() => {\n    const id = setTimeout(() => setDebounced(value), delay);\n    return () => clearTimeout(id);\n  }, [value, delay]);\n  return debounced;\n}\n\nexport default function SearchBox() {\n  const [q, setQ] = useState('');\n  const debouncedQ = useDebouncedValue(q, 300);\n  const [items, setItems] = useState([]);\n  const [loading, setLoading] = useState(false);\n  const [error, setError] = useState(null);\n\n  const controller = useMemo(() => new AbortController(), [debouncedQ]);\n\n  useEffect(() => {\n    if (!debouncedQ) { setItems([]); return; }\n    setLoading(true); setError(null);\n\n    fetch(`/search?q=${encodeURIComponent(debouncedQ)}`, { signal: controller.signal })\n      .then(r => {\n        if (!r.ok) throw new Error('Network error');\n        return r.json();\n      })\n      .then(data => setItems(data.items || []))\n      .catch(err => { if (err.name !== 'AbortError') setError(err.message); })\n      .finally(() => setLoading(false));\n\n    return () => controller.abort();\n  }, [debouncedQ]);\n\n  return (\n    <div>\n      <input\n        placeholder=\"Поиск...\"\n        value={q}\n        onChange={e => setQ(e.target.value)}\n      />\n      {loading && <div>Загрузка...</div>}\n      {error && <div>Ошибка: {error}</div>}\n      {!loading && !error && items.length === 0 && debouncedQ && <div>Ничего не найдено</div>}\n      <ul>\n        {items.map(i => <li key={i.id}>{i.title}</li>)}\n      </ul>\n    </div>\n  );\n}"
      }]
    },
    {
      "type": "heading",
      "attrs": { "level": 3 },
      "content": [{ "type": "text", "text": "Алгоритмический аспект: бинарный поиск" }]
    },
    {
      "type": "codeBlock",
      "content": [{
        "type": "text",
        "text": "function binarySearch(arr, x) {\n  let l = 0, r = arr.length - 1;\n  while (l <= r) {\n    const m = l + ((r - l) >> 1);\n    if (arr[m] === x) return m;\n    if (arr[m] < x) l = m + 1; else r = m - 1;\n  }\n  return -1;\n}\n\n// Использование: массив должен быть отсортирован\nconsole.log(binarySearch([1,3,5,7,9], 7)); // 3"
      }]
    },
    {
      "type": "heading",
      "attrs": { "level": 3 },
      "content": [{ "type": "text", "text": "Чек-лист внедрения поиска" }]
    },
    {
      "type": "orderedList",
      "content": [
        { "type": "listItem", "content": [{ "type": "paragraph", "content": [{ "type": "text", "text": "Собрать требования: типы контента, поля, язык, нагрузки, SLA." }] }] },
        { "type": "listItem", "content": [{ "type": "paragraph", "content": [{ "type": "text", "text": "Выбрать технологию: БД с FTS или специализированный движок; оценить стоимость и поддержку." }] }] },
        { "type": "listItem", "content": [{ "type": "paragraph", "content": [{ "type": "text", "text": "Схема данных и индексы: какие поля индексируются, морфология, синонимы, токенизация." }] }] },
        { "type": "listItem", "content": [{ "type": "paragraph", "content": [{ "type": "text", "text": "Пайплайн индексации: источники, очереди, дедупликация, обновления, контроль отставания." }] }] },
        { "type": "listItem", "content": [{ "type": "paragraph", "content": [{ "type": "text", "text": "API: фильтры, сортировки, пагинация, подсветка, безопасность на уровне запросов." }] }] },
        { "type": "listItem", "content": [{ "type": "paragraph", "content": [{ "type": "text", "text": "UI/UX: подсказки, автодополнение, фасеты, пустые состояния, доступность (a11y)." }] }] },
        { "type": "listItem", "content": [{ "type": "paragraph", "content": [{ "type": "text", "text": "Наблюдаемость: логирование запросов, метрики, трейсинг, дашборды, алерты." }] }] },
        { "type": "listItem", "content": [{ "type": "paragraph", "content": [{ "type": "text", "text": "Качество и релевантность: офлайн/онлайн оценки, A/B-тесты, сбор кликов для обучения." }] }] },
        { "type": "listItem", "content": [{ "type": "paragraph", "content": [{ "type": "text", "text": "Эксплуатация: бэкапы, реиндексация без даунтайма, шардирование/репликация, план обновлений." }] }] }
      ]
    }
  ]
}

{"type":"doc","content":[{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Короткий ответ"}]},{"type":"paragraph","content":[{"type":"text","text":"Линейный поиск — это простой алгоритм поиска элемента в массиве (или списке), который последовательно проверяет каждый элемент с начала до конца, пока не найдёт искомый или не переберёт все элементы."}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Работает на неотсортированных данных."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Время: O(n), память: O(1)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Возвращает индекс найденного элемента (или -1/false, если не найден)."}]}]}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Развернутый ответ"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Определение и идея"}]},{"type":"paragraph","content":[{"type":"text","text":"Линейный поиск (sequential search) последовательно сравнивает целевой элемент (target) с каждым элементом структуры данных. Он не требует предварительной сортировки и подходит для произвольных коллекций, в том числе для потоковых или связанных списков."}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Алгоритм (шаги)"}]},{"type":"orderedList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Начать с первого элемента."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Сравнить текущий элемент с искомым."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Если совпадает — вернуть его позицию/значение."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Иначе перейти к следующему элементу и повторять до конца."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Если элементы закончились — сообщить, что не найдено."}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Сложность"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Время: O(n) в среднем и в худшем случае (смотрим весь массив); O(1) в лучшем (первый же элемент)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Память: O(1) — дополнительной памяти практически не требует."}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Когда использовать"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Данные не отсортированы и сортировка нецелесообразна."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Малые массивы или выполняется мало поисковых запросов."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Данные приходят потоком (итеративный доступ), например, связанный список."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Нужно просто проверить наличие элемента (predicate-поиск)."}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Псевдокод"}]},{"type":"codeBlock","attrs":{"language":"text"},"content":[{"type":"text","text":"function linear_search(A, target):
  for i from 0 to length(A) - 1:
    if A[i] == target:
      return i
  return -1"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Реализация: JavaScript"}]},{"type":"codeBlock","attrs":{"language":"javascript"},"content":[{"type":"text","text":"// Возвращает индекс найденного элемента или -1
function linearSearch(arr, target) {
  for (let i = 0; i < arr.length; i++) {
    if (Object.is(arr[i], target) || arr[i] === target) { // корректно обрабатывает NaN
      return i;
    }
  }
  return -1;
}

// Вариант, возвращающий boolean
function includesLinear(arr, target) {
  return linearSearch(arr, target) !== -1;
}

// Вариант с предикатом (гибче для объектов)
function findIndexLinear(arr, predicate) {
  for (let i = 0; i < arr.length; i++) {
    if (predicate(arr[i], i, arr)) return i;
  }
  return -1;
}

function findLinear(arr, predicate) {
  const idx = findIndexLinear(arr, predicate);
  return idx === -1 ? undefined : arr[idx];
}"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Пример использования"}]},{"type":"codeBlock","attrs":{"language":"javascript"},"content":[{"type":"text","text":"const nums = [5, 2, 9, 1, 5, 6];
console.log(linearSearch(nums, 9));   // 2
console.log(linearSearch(nums, 7));   // -1
console.log(includesLinear(nums, 1)); // true

const users = [
  { id: 10, name: 'Ana' },
  { id: 20, name: 'Ben' },
  { id: 30, name: 'Cat' },
];

const idxBen = findIndexLinear(users, u => u.name === 'Ben');
console.log(idxBen); // 1

const user30 = findLinear(users, u => u.id === 30);
console.log(user30); // { id: 30, name: 'Cat' }"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Пошаговая иллюстрация"}]},{"type":"paragraph","content":[{"type":"text","text":"Ищем 5 в [3, 4, 5, 2]: сравниваем по порядку: 3 (нет), 4 (нет), 5 (да) — возвращаем индекс 2."}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Особые случаи и нюансы"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Дубликаты: обычно возвращают первый найденный индекс."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Сравнение в JS: Object.is корректно работает с NaN и различает +0/-0; сочетание Object.is || === покрывает основные случаи."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Ранний выход: как только найден элемент, цикл завершается (лучшая-case производительность)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Поиск по объектам: используйте предикат/компаратор, а не сравнение ссылок, если нужно сравнить по полю."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Для очень больших наборов данных и частых запросов выгоднее предварительно построить индекс (Map/Set) или отсортировать и применять бинарный поиск."}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Сравнение с бинарным поиском"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Требование к данным: линейный — любые; бинарный — только отсортированные."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Сложность: O(n) vs O(log n) на поиск; но у бинарного есть стоимость сортировки O(n log n) и поддержания порядка при изменениях."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Выбор: при единичных поисках по неотсортированному массиву линейный проще и иногда быстрее из-за малых констант."}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Тестовые случаи"}]},{"type":"codeBlock","attrs":{"language":"javascript"},"content":[{"type":"text","text":"console.assert(linearSearch([], 1) === -1);
console.assert(linearSearch([1], 1) === 0);
console.assert(linearSearch([2, 3, 4], 1) === -1);
console.assert(linearSearch([2, 3, 1, 4], 1) === 2);
console.assert(linearSearch([NaN], NaN) === 0);
console.assert(findIndexLinear([{a:1},{a:2}], o => o.a === 2) === 1);"}]}]}

