    {
      "type": "codeBlock",
      "attrs": { "language": "javascript" },
      "content": [
        {
          "type": "text",
          "text": "function binarySearch(arr, target) {\n  let left = 0;\n  let right = arr.length - 1;\n  while (left <= right) {\n    const mid = left + ((right - left) >> 1); // безопаснее, чем (left + right) >> 1\n    if (arr[mid] === target) return mid;\n    if (arr[mid] < target) left = mid + 1;\n    else right = mid - 1;\n  }\n  return -1; // не найдено\n}\n\n// Пример\nconst a = [1, 3, 4, 7, 9, 12, 18];\nconsole.log(binarySearch(a, 9));  // 4\nconsole.log(binarySearch(a, 2));  // -1"
        }
