      "type": "codeBlock",
      "attrs": { "language": "javascript" },
      "content": [
        {
          "type": "text",
          "text": "function lowerBound(arr, target) {\n  let left = 0, right = arr.length; // полуинтервал [left, right)\n  while (left < right) {\n    const mid = left + ((right - left) >> 1);\n    if (arr[mid] < target) left = mid + 1;\n    else right = mid;\n  }\n  return left; // первый индекс, где arr[i] >= target\n}\n\n// Использование для \"первого равного\"\nconst b = [1, 3, 3, 3, 5, 8];\nconst idx = lowerBound(b, 3);\nconst exists = idx < b.length && b[idx] === 3; // true\nconsole.log(idx, exists); // 1 true"
        }
