    },
    {
      "type": "codeBlock",
      "attrs": { "language": "javascript" },
      "content": [
        {
          "type": "text",
          "text": "// Пример: минимальная грузоподъёмность, чтобы перевезти weights за days (классическая задача)\nfunction minCapacity(weights, days) {\n  let left = Math.max(...weights);\n  let right = weights.reduce((s, x) => s + x, 0);\n  const can = cap => {\n    let need = 1, sum = 0;\n    for (const w of weights) {\n      if (sum + w > cap) { need++; sum = 0; }\n      sum += w;\n    }\n    return need <= days;\n  };\n  while (left < right) {\n    const mid = left + ((right - left) >> 1);\n    if (can(mid)) right = mid; else left = mid + 1;\n  }\n  return left;\n}"
        }
      ]
