// l=3, r=4, mid=3 -> arr[3]=7. x<7 => идём влево (r=2)
// Теперь l=3, r=2 => цикл заканчивается, возвращаем -1, хотя 5 есть (index=4)
// Ошибка из-за отсутствия глобального порядка: сравнение с серединой не гарантирует, что слева/справа нет ответа."}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Дубликаты, компаратор и требования к порядку"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Допускаются дубликаты. Нужно определить цель: любой индекс элемента, первый (lower_bound) или последний (upper_bound)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Порядок должен быть тотальным и транзитивным по одному и тому же компаратору, которым массив отсортирован и по которому выполняются сравнения в поиске. Несогласованный компаратор нарушит инварианты."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Особые значения (например, NaN) нарушают сравнимость: их нужно обрабатывать отдельно или исключать."}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Обобщение через монотонный предикат (lower_bound)"}]},{"type":"paragraph","content":[{"type":"text","text":"Бинарный поиск на самом деле ищет границу, где предикат P(i) меняется с false на true. В отсортированном по возрастанию массиве предикат P(i): a[i] ≥ x монотонен, поэтому можно найти первый индекс, где элемент не меньше x (lower_bound)."}]},{"type":"codeBlock","content":[{"type":"text","text":"function lowerBound(arr, x) {
  // Возвращает минимальный индекс i, такой что arr[i] >= x.
  // Если такого нет — возвращает arr.length.
  let l = 0, r = arr.length; // полуинтервал [l, r)
  while (l < r) {
    const mid = l + ((r - l) >> 1);
    if (arr[mid] >= x) r = mid; // true-зона
    else l = mid + 1;           // false-зона
  }
  return l;
}

const a = [1, 3, 3, 5, 8];
console.log(lowerBound(a, 3)); // 1 (первый индекс с 3)
console.log(lowerBound(a, 4)); // 3 (первый индекс с >=4 — это 5)
console.log(lowerBound(a, 9)); // 5 (нет таких элементов)"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Практические выводы и сложности"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Если нужен один поиск по неотсортированным данным, используйте линейный проход O(n)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Если поисков много, выгодно отсортировать один раз за O(n log n) и затем выполнять O(log n) на каждый запрос."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Для динамических данных поддерживайте структуру с порядком (например, отсортированный массив с бинарным поиском и вставками через бинарный поиск + сплайс; либо дерево/индекс), чтобы сохранялась монотонность, необходимая двоичному поиску."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Бинарный поиск применим не только к массивам: он работает на любой упорядоченной области значений/ответов, где есть монотонный критерий достижимости/выполнимости."}]}]}]}]}

{"type":"doc","content":[{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Короткий ответ"}]},{"type":"paragraph","content":[{"type":"text","text":"Бинарное дерево поиска (BST) — это структура данных, где для каждой вершины все ключи в левом поддереве меньше ключа вершины, а в правом — больше. Благодаря этому BST позволяет эффективно искать, вставлять и удалять элементы в среднем за O(log n), а симметричный обход (in-order) возвращает элементы в отсортированном порядке."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Развернутый ответ"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Что такое BST и зачем оно нужно"}]},{"type":"paragraph","content":[{"type":"text","text":"BST организует динамический набор сравнимых ключей таким образом, чтобы быстро выполнять операции поиска, вставки, удаления и получать элементы в отсортированном порядке без дополнительной сортировки. Применяется для реализаций множеств и словарей с упорядочением, диапазонных запросов, поиска ближайших значений, предшественника/последователя и т. п."}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Инварианты BST"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Для каждой вершины: все ключи в левом поддереве < ключ вершины, все ключи в правом поддереве > ключ вершины."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Инвариант рекурсивен: он выполняется для каждой вершины дерева."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Политика дубликатов — на выбор: запрет, счётчик частоты, хранение коллекции или направлять равные ключи в одну из сторон (в примере — вправо)."}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Сложность операций"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Поиск/вставка/удаление: среднее O(log n), худшее O(n) при вырождении (если дерево становится «цепочкой»)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Обход (in-order, pre-order, post-order): O(n)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Память: O(n). Высота h влияет на операции: чем меньше h, тем быстрее."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Сбалансированные варианты (AVL, красно-чёрные деревья и др.) гарантируют O(log n) в худшем случае."}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Основные операции"}]},{"type":"orderedList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Поиск: начинаем с корня и идём влево или вправо в зависимости от сравнения ключа с ключом текущей вершины, пока не найдём или не упремся в пустоту."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Вставка: ищем место как при поиске и вставляем новый узел в найденную пустую позицию, сохраняя инвариант."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Удаление: три случая относительно удаляемого узла."}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Лист: просто удаляем."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Один ребёнок: подтягиваем ребёнка на место узла."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Два ребёнка: заменяем ключ (и значение) узла на ключ его in-order преемника (минимум в правом поддереве) и удаляем преемника из правого поддерева."}]}]}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Обходы: симметричный (in-order) возвращает отсортированную последовательность ключей."}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Pre-order (корень, левое, правое) — сериализация структуры."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"In-order (левое, корень, правое) — отсортированный вывод."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Post-order (левое, правое, корень) — удаление/освобождение."}]}]}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Пример кода (JavaScript)"}]},{"type":"paragraph","content":[{"type":"text","text":"Политика дубликатов: равные ключи направляем вправо. Можно передать свою функцию сравнения."}]},{"type":"codeBlock","content":[{"type":"text","text":"class Node {
  constructor(key, value = null) {
    this.key = key;
    this.value = value;
    this.left = null;
    this.right = null;
  }
}

class BST {
  constructor(compareFn) {
    this.root = null;
    this.compare = compareFn || ((a, b) => (a < b ? -1 : a > b ? 1 : 0));
  }

  contains(key) {
    let cur = this.root;
    while (cur) {
      const c = this.compare(key, cur.key);
      if (c === 0) return true;
      cur = c < 0 ? cur.left : cur.right;
    }
    return false;
  }

  search(key) {
    let cur = this.root;
    while (cur) {
      const c = this.compare(key, cur.key);
      if (c === 0) return cur.value ?? cur.key;
      cur = c < 0 ? cur.left : cur.right;
    }
    return undefined;
  }

  insert(key, value = null) {
    const node = new Node(key, value);
    if (!this.root) {
      this.root = node;
      return this;
    }
    let cur = this.root;
    while (true) {
      const c = this.compare(key, cur.key);
      if (c < 0) {
        if (!cur.left) { cur.left = node; break; }
        cur = cur.left;
      } else { // c >= 0 — дубликаты направляем вправо
        if (!cur.right) { cur.right = node; break; }
        cur = cur.right;
      }
    }
    return this;
  }

  min(node = this.root) {
    if (!node) return undefined;
    while (node.left) node = node.left;
    return node.key;
  }

  max(node = this.root) {
    if (!node) return undefined;
    while (node.right) node = node.right;
    return node.key;
  }

  remove(key) {
    this.root = this.#removeNode(this.root, key);
    return this;
  }

  #removeNode(node, key) {
    if (!node) return null;
    const c = this.compare(key, node.key);
    if (c < 0) {
      node.left = this.#removeNode(node.left, key);
      return node;
    } else if (c > 0) {
      node.right = this.#removeNode(node.right, key);
      return node;
    } else {
      // Случай 1: лист
      if (!node.left && !node.right) return null;
      // Случай 2: один ребёнок
      if (!node.left) return node.right;
      if (!node.right) return node.left;
      // Случай 3: два ребёнка — берём преемника (минимум в правом поддереве)
      let succ = node.right;
      while (succ.left) succ = succ.left;
      node.key = succ.key;
      node.value = succ.value;
      node.right = this.#removeNode(node.right, succ.key);
      return node;
    }
  }

  traverseInOrder(cb, node = this.root) {
    if (!node) return;
    this.traverseInOrder(cb, node.left);
    cb(node);
    this.traverseInOrder(cb, node.right);
  }

  traversePreOrder(cb, node = this.root) {
    if (!node) return;
    cb(node);
    this.traversePreOrder(cb, node.left);
    this.traversePreOrder(cb, node.right);
  }

  traversePostOrder(cb, node = this.root) {
    if (!node) return;
    this.traversePostOrder(cb, node.left);
    this.traversePostOrder(cb, node.right);
    cb(node);
  }

  height(node = this.root) {
    if (!node) return -1; // высота пустого дерева
    return 1 + Math.max(this.height(node.left), this.height(node.right));
  }
}
"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Примеры использования"}]},{"type":"codeBlock","content":[{"type":"text","text":"const bst = new BST();
[8, 3, 10, 1, 6, 14, 4, 7, 13].forEach(k => bst.insert(k));

console.log('contains 7?', bst.contains(7)); // true
console.log('min/max:', bst.min(), bst.max()); // 1 14

const sorted = [];
bst.traverseInOrder(n => sorted.push(n.key));
console.log('sorted:', sorted.join(', ')); // 1, 3, 4, 6, 7, 8, 10, 13, 14

bst.remove(3);
const after = [];
bst.traverseInOrder(n => after.push(n.key));
console.log('after delete 3:', after.join(', '));

console.log('height:', bst.height());

// Диапазонный запрос [4, 10]
const range = [];
bst.traverseInOrder(n => {
  if (n.key >= 4 && n.key <= 10) range.push(n.key);
});
console.log('range [4..10]:', range.join(', '));
"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Когда BST — хороший выбор"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Нужен упорядоченный набор с частыми вставками/удалениями и быстрым поиском."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Диапазонные запросы (все ключи между L и R), поиск предшественника/последователя."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Нужно получать элементы в сортированном порядке «на лету» (in-order обход)."}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Подводные камни и советы"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Вырождение в худшем случае: выбирайте случайные вставки или используйте самобалансирующиеся деревья для гарантий O(log n)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Определите и придерживайтесь политики дубликатов (запрет, счётчик, направление вправо/влево)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Функция сравнения должна задавать строгий слабый порядок (транзитивность, антирефлексивность) — иначе дерево сломается."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Рекурсивные реализации проще, но могут упереться в лимит стека на очень глубоких деревьях; при необходимости используйте итеративные версии."}]}]}]}]}

