          "type": "text",
          "text": "function exponentialSearch(arr, target) {\n  const n = arr.length;\n  if (n === 0) return -1;\n  if (arr[0] === target) return 0;\n\n  // Экспоненциальное расширение диапазона\n  let bound = 1;\n  while (bound < n && arr[bound] < target) {\n    bound *= 2;\n  }\n\n  const left = Math.floor(bound / 2);\n  const right = Math.min(bound, n - 1);\n  return binarySearchInRange(arr, target, left, right);\n}\n\nfunction binarySearchInRange(arr, target, left, right) {\n  while (left <= right) {\n    const mid = left + ((right - left) >> 1);\n    if (arr[mid] === target) return mid; // Для первой позиции см. вариант ниже\n    if (arr[mid] < target) left = mid + 1;\n    else right = mid - 1;\n  }\n  return -1;\n}\n\n// Вариант, возвращающий индекс ПЕРВОГО вхождения при дубликатах\nfunction binarySearchFirst(arr, target, left, right) {\n  let ans = -1;\n  while (left <= right) {\n    const mid = left + ((right - left) >> 1);\n    if (arr[mid] >= target) {\n      if (arr[mid] === target) ans = mid;\n      right = mid - 1;\n    } else {\n      left = mid + 1;\n    }\n  }\n  return ans;\n}\n\n// Пример использования:\n// const idx = exponentialSearch([1,3,5,7,9,12,15,18,21], 12); // => 5"
